SELECT /* base.ec.cm :: CmBlogGood :: selectList */ g.* , blt.blog_title AS blog_nm FROM cm_blog_good g LEFT JOIN cm_blog blt ON blt.blog_id = g.blog_id
ORDER BY g.like_id ASC ORDER BY g.like_id DESC ORDER BY g.reg_date ASC ORDER BY g.reg_date DESC ORDER BY g.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

